import html

def prevent_xss(text: str) -> str:
    """
    Bu fonksiyon, metni HTML çıktısı için güvenli hale getirerek
    temel XSS (Cross-Site Scripting) saldırılarını önler.
    HTML özel karakterlerini (örneğin <, >, &, ", ') HTML varlıklarına dönüştürür.
    """
    if not isinstance(text, str):
        text = str(text)
    return html.escape(text, quote=True)
